def parse_rounds(round_value=None, round_range=None):
    rounds = set()
    if round_value:
        for part in str(round_value).split(","):
            part = part.strip()
            if part:
                rounds.add(int(part))
    if round_range:
        start, end = str(round_range).split("-", 1)
        rounds.update(range(int(start), int(end) + 1))
    return sorted(rounds)


